import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"东交民巷天主堂","description":"","frontmatter":{},"headers":[],"relativePath":"religion/dongjiaominxiang.md","filePath":"religion/dongjiaominxiang.md","lastUpdated":null}'),n={name:"religion/dongjiaominxiang.md"};function i(o,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="东交民巷天主堂" tabindex="-1">东交民巷天主堂 <a class="header-anchor" href="#东交民巷天主堂" aria-label="Permalink to &quot;东交民巷天主堂&quot;">​</a></h1><blockquote><p>&quot;使馆区中的百年教堂，近代历史的见证。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>东交民巷天主堂，又称圣米厄尔教堂，位于北京市东城区东交民巷，是北京著名的天主教堂之一。教堂建于1901年，由法国传教士在东交民巷使馆区修建，具有典型的哥特式建筑风格。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-20:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟</td></tr><tr><td style="text-align:left;"><strong>弥撒时间</strong></td><td style="text-align:left;">周日6:30、8:00、10:00</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线/5号线崇文门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区东交民巷甲13号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>东交民巷天主堂建于清光绪二十七年（1901年），由法国传教士主持修建。当时东交民巷是各国使馆区，教堂主要为外交人员服务。</p><h3 id="建筑风格" tabindex="-1">建筑风格 <a class="header-anchor" href="#建筑风格" aria-label="Permalink to &quot;建筑风格&quot;">​</a></h3><p>教堂采用哥特式建筑风格，与北京其他天主教堂不同，具有典型的法国哥特式建筑特点。</p><h3 id="近代" tabindex="-1">近代 <a class="header-anchor" href="#近代" aria-label="Permalink to &quot;近代&quot;">​</a></h3><p>1958年，教堂关闭。1989年，修复后重新开放。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="哥特式建筑" tabindex="-1">哥特式建筑 <a class="header-anchor" href="#哥特式建筑" aria-label="Permalink to &quot;哥特式建筑&quot;">​</a></h3><p>东交民巷天主堂是北京少数几座哥特式教堂之一。</p><h4 id="外观特点" tabindex="-1">外观特点 <a class="header-anchor" href="#外观特点" aria-label="Permalink to &quot;外观特点&quot;">​</a></h4><ul><li><strong>尖塔</strong>：高耸的尖塔直指苍穹</li><li><strong>尖拱</strong>：门窗采用尖拱造型</li><li><strong>彩色玻璃</strong>：彩色玻璃窗描绘圣经故事</li><li><strong>飞扶壁</strong>：典型的哥特式结构</li></ul><h4 id="内部" tabindex="-1">内部 <a class="header-anchor" href="#内部" aria-label="Permalink to &quot;内部&quot;">​</a></h4><p>教堂内部空间不大，但庄严肃穆。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>面积</strong></td><td style="text-align:left;">约400平方米</td></tr><tr><td style="text-align:left;"><strong>容量</strong></td><td style="text-align:left;">可容纳400余人</td></tr><tr><td style="text-align:left;"><strong>祭台</strong></td><td style="text-align:left;">主祭台供奉圣米厄尔像</td></tr><tr><td style="text-align:left;"><strong>装饰</strong></td><td style="text-align:left;">内部装饰精美</td></tr></tbody></table><h2 id="东交民巷" tabindex="-1">东交民巷 <a class="header-anchor" href="#东交民巷" aria-label="Permalink to &quot;东交民巷&quot;">​</a></h2><h3 id="使馆区历史" tabindex="-1">使馆区历史 <a class="header-anchor" href="#使馆区历史" aria-label="Permalink to &quot;使馆区历史&quot;">​</a></h3><p>东交民巷在清末至民国时期是各国使馆区，有&quot;使馆街&quot;之称。英国、法国、美国、俄国、日本、德国等国使馆均设于此。</p><h3 id="近代建筑" tabindex="-1">近代建筑 <a class="header-anchor" href="#近代建筑" aria-label="Permalink to &quot;近代建筑&quot;">​</a></h3><p>东交民巷保存了大量近代西式建筑，包括：</p><ul><li><strong>英国使馆旧址</strong></li><li><strong>法国使馆旧址</strong></li><li><strong>美国使馆旧址</strong></li><li><strong>日本公使馆旧址</strong></li><li><strong>正金银行旧址</strong></li></ul><h3 id="历史意义" tabindex="-1">历史意义 <a class="header-anchor" href="#历史意义" aria-label="Permalink to &quot;历史意义&quot;">​</a></h3><p>东交民巷见证了近代中国屈辱的历史，《辛丑条约》签订后，东交民巷成为外国人的&quot;国中之国&quot;。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>教堂参观（约30分钟）</strong>：</p><p>东交民巷 → 教堂参观 → 周边近代建筑</p><p><strong>东交民巷漫步（约1小时）</strong>：</p><p>崇文门 → 东交民巷 → 教堂 → 各国使馆旧址 → 天安门广场</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线/5号线崇文门站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">8路、9路、41路等崇文门内站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从前门步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>使馆区历史</strong>：了解东交民巷的近代历史</li><li><strong>建筑风格</strong>：典型的哥特式建筑</li><li><strong>保持安静</strong>：保持安静</li><li><strong>结合游览</strong>：可与前门、天安门一起游览</li><li><strong>拍照注意</strong>：部分建筑可能不允许拍照</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">前门大街</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">老北京商业街</td></tr><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">世界最大广场</td></tr><tr><td style="text-align:left;">国家博物馆</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">国家级博物馆</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">明清皇宫</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>东交民巷天主堂是北京近代历史的见证，也是中西文化交流的产物。</p><p>东交民巷是近代中国屈辱历史的见证，游览这里，可以了解那段历史，铭记历史，珍爱和平。</p><hr><p><strong>📍 地址</strong>：北京市东城区东交民巷甲13号 <strong>📞 电话</strong>：010-65243341</p>',46)])])}const b=e(n,[["render",i]]);export{f as __pageData,b as default};
